1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block unchanged (still life)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(result.slice().sort()).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]].sort());
17	  });
18	  it("should transform vertical blinker into horizontal blinker", () => {
19	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
20	    expect(result.slice().sort()).toEqual([[-1, 1], [0, 1], [1, 1]].sort());
21	  });
22	  it("should kill a live cell with 4 live neighbors (overpopulation)", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]]);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
27	    const result = nextGeneration([[0, 2], [1, 2], [0, 1]]);
28	    expect(result).toContainEqual([1, 1]);
29	  });
30	  it.todo("should handle cells with negative coordinates");
31	});
